// FR-07: Shopping Cart — DOM Check Suite
// Generated by: test-execution-assistant skill
//
// Instructions:
//   1. Navigate browser to: http://localhost:5173/cart
//   2. Open DevTools: F12 → Console tab
//   3. Paste this entire script content and press Enter
//   4. Screenshot the console output
//   5. Copy the printed summary and paste into Phase B prompt
// =============================================================================

(function FR07DOMChecks() {
  "use strict";

  let pass = 0, fail = 0;
  const results = [];

  function check(tcId, description, expected, actualFn) {
    let actual, status;
    try {
      actual = actualFn();
      const ok = String(actual) === String(expected);
      status = ok ? "PASS" : "FAIL";
    } catch (e) {
      actual = "ERROR: " + e.message;
      status = "FAIL";
    }
    status === "PASS" ? pass++ : fail++;
    results.push({ tcId, description, expected, actual, status });
  }

  // ── FR07-EP-006: XSS Payload ────────────────────────────────────────────────
  check(
    "FR07-EP-006",
    "No raw <script> tag injected into DOM (per SEC-04)",
    "SAFE",
    () => {
      return document.body.innerHTML.includes("<script>alert(1)</script>")
        ? "VULNERABLE"
        : "SAFE";
    }
  );

  // ── Standard library checks ─────────────────────────────────────────────────
  // FR07-DOM-H1: Exactly 1 <h1> tag
  check("FR07-DOM-H1", "Page has exactly 1 <h1> tag (per FR-21)", "1", () =>
    String(document.querySelectorAll("h1").length)
  );

  // FR07-DOM-UI: Check "Tổng cộng" label
  check(
    "FR07-DOM-TOTAL",
    "Display 'Tổng cộng' (not 'Tổng tạm tính')",
    "EXISTS",
    () => {
      const pageText = document.body.innerText || document.body.textContent;
      if (pageText.includes("Tổng tạm tính")) {
        return "FOUND_WRONG_LABEL: Tổng tạm tính";
      }
      if (pageText.includes("Tổng cộng")) {
        return "EXISTS";
      }
      return "NOT_FOUND";
    }
  );

  // FR07-DOM-UI: Check "Tiếp tục mua sắm" OR "Mua tiếp" button
  check(
    "FR07-DOM-BTN",
    "Display 'Tiếp tục mua sắm' or 'Mua tiếp' button",
    "EXISTS",
    () => {
      const clickableElements = Array.from(document.querySelectorAll("button, a"));
      const continueBtn = clickableElements.find(
        (el) => el.textContent && (el.textContent.includes("Tiếp tục mua sắm") || el.textContent.includes("Mua tiếp"))
      );
      return continueBtn ? "EXISTS" : "NOT_FOUND";
    }
  );

  console.log("%c\n========================================", "font-weight: bold;");
  console.log("%c FR-07 DOM CHECK RESULTS                ", "font-weight: bold;");
  console.log("%c========================================", "font-weight: bold;");

  results.forEach((r) => {
    const c = r.status === "PASS" ? "color: green" : "color: red; font-weight: bold";
    console.log(`%c[${r.status}] ${r.tcId} — ${r.description}`, c);
    console.log(`%c      Expected: ${r.expected} | Actual: ${r.actual}`, c);
  });

  console.log("%c========================================", "font-weight: bold;");
  console.log(
    `TOTAL: %c${pass} PASS%c | %c${fail} FAIL`,
    "color: green; font-weight: bold",
    "color: inherit",
    "color: red; font-weight: bold"
  );
})();
